using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // Breaking change 1: EF Core 9 renamed the default discriminator
            // property from "Discriminator" to "$type". Existing 500K documents
            // store "Discriminator", so we must keep the old name.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: EF Core 9 changed the default id format from
            // "Product|123" to just "123". Existing documents use the old format,
            // so we preserve it with a custom value generator.
            b.Property<string>("__id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();

            // Breaking change 4: HasIndex now throws for the Cosmos provider
            // (it was silently ignored in EF Core 8). Removed.
        });
    }
}

/// <summary>
/// Preserves the EF Core 8 Cosmos id format: "EntityType|PrimaryKey".
/// Required so EF Core 9 can read/write documents written by EF Core 8.
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
        => $"{entry.Metadata.ShortName()}|{entry.Property("Id").CurrentValue}";
}

class Product { public int Id { get; set; } public string Sku { get; set; } }

