{
    // Breaking change 3: EF Core 9 removed synchronous I/O from the Cosmos
    // provider. All queries must use async APIs (ToListAsync, FirstAsync, etc.).
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — works because we kept "Discriminator" as the
        // discriminator property name in OnModelCreating.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

